  {id:70,home:'COD',away:'UZB'},{id:71,home:'JOR',away:'ARG'},{id:72,home:'ALG',away:'AUT'}
];

const toUpdate = [];

const pattern = /<span>([A-Z]{2,4})<\/span>[\s\S]{1,500}?<div class="text-xl text-center">(\d*)<\/div>[\s\S]{1,700}?<div class="text-xl text-center">(\d*)<\/div>[\s\S]{1,500}?<span>([A-Z]{2,4})<\/span>/g;

let m;
while ((m = pattern.exec(html)) !== null) {
  const widgetHome = m[1];
  const scoreHome  = m[2];
  const scoreAway  = m[3];
  const widgetAway = m[4];

  if (scoreHome === '' || scoreAway === '') continue;

  const homeCode = WIDGET_MAP[widgetHome];
  const awayCode = WIDGET_MAP[widgetAway];
  if (!homeCode || !awayCode) continue;

  const localMatch = MATCHES.find(x => x.home === homeCode && x.away === awayCode);
  if (!localMatch) continue;

  if (!toUpdate.find(u => u.id === localMatch.id)) {
    toUpdate.push({
      id: localMatch.id,
      home_score: parseInt(scoreHome),
      away_score: parseInt(scoreAway),
      label: homeCode + ' ' + scoreHome + 'x' + scoreAway + ' ' + awayCode
    });
    console.log('Placar encontrado:', homeCode, scoreHome, 'x', scoreAway, awayCode);
  }
}

console.log('Total para atualizar:', toUpdate.length);

if (toUpdate.length === 0) {
  return [{ json: { debug: true, found: 0 } }];
}

return toUpdate.map(item => ({ json: item }));
